// src/components/Comments.jsx
// Features: real-time comments, @mention author, reply threads, delete
import { useState, useEffect, useRef } from "react";
import { subscribeToComments, addComment, deleteComment } from "../firebase/posts";

function timeAgo(ts) {
  if (!ts) return "just now";
  const d = ts.seconds ? new Date(ts.seconds * 1000) : new Date(ts);
  const diff = (Date.now() - d) / 1000;
  if (diff < 60)    return "just now";
  if (diff < 3600)  return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
}

// Render text with @mentions highlighted in blue
function RenderText({ text }) {
  const parts = text.split(/(@\w[\w\s]*)/g);
  return (
    <span>
      {parts.map((part, i) =>
        part.startsWith("@")
          ? <span key={i} style={{ color: "var(--blue)", fontWeight: 700, fontFamily: "var(--font-display)" }}>{part}</span>
          : <span key={i}>{part}</span>
      )}
    </span>
  );
}

export default function Comments({ postId, postAuthor, isDemo, currentUser }) {
  const [comments, setComments]         = useState([]);
  const [localComments, setLocalComments] = useState([]);
  const [text, setText]                 = useState("");
  const [replyTo, setReplyTo]           = useState(null); // { id, name }
  const [submitting, setSubmitting]     = useState(false);
  const [showAll, setShowAll]           = useState(false);
  const inputRef = useRef();

  useEffect(() => {
    if (isDemo) return;
    const unsub = subscribeToComments(postId, setComments);
    return unsub;
  }, [postId, isDemo]);

  const displayed = isDemo ? localComments : comments;
  const visible   = showAll ? displayed : displayed.slice(0, 5);

  // When user clicks "Reply" or "@mention", insert into textarea
  const handleMention = (name) => {
    const mention = `@${name} `;
    setText((prev) => (prev.startsWith("@") ? mention : mention + prev));
    setReplyTo({ name });
    inputRef.current?.focus();
  };

  const handleMentionAuthor = () => handleMention(postAuthor);

  const handleSubmit = async () => {
    if (!text.trim()) return;
    setSubmitting(true);

    const displayName = currentUser?.displayName || "Anonymous";
    const comment = {
      name:      displayName,
      uid:       currentUser?.uid || null,
      photoURL:  currentUser?.photoURL || null,
      text:      text.trim(),
      replyTo:   replyTo?.name || null,
      postId,
    };

    try {
      if (isDemo) {
        setLocalComments((p) => [
          ...p,
          { id: Date.now().toString(), ...comment, createdAt: { seconds: Date.now() / 1000 } },
        ]);
      } else {
        await addComment(postId, comment);
      }
      setText("");
      setReplyTo(null);
    } catch (e) { console.error(e); }
    setSubmitting(false);
  };

  const handleDelete = async (cid) => {
    if (isDemo) {
      setLocalComments((p) => p.filter((c) => c.id !== cid));
    } else {
      await deleteComment(postId, cid);
    }
  };

  const canDelete = (c) =>
    currentUser && (currentUser.uid === c.uid);

  return (
    <div style={s.wrap}>
      {/* Header */}
      <div style={s.header}>
        <h3 style={s.heading}>
          💬 Comments
          <span style={s.badge}>{displayed.length}</span>
        </h3>

        {/* Tag the author button */}
        {postAuthor && (
          <button style={s.mentionAuthorBtn} onClick={handleMentionAuthor}>
            📢 Tag @{postAuthor}
          </button>
        )}
      </div>

      {/* Reply indicator */}
      {replyTo && (
        <div style={s.replyBanner}>
          <span>Replying to <strong>@{replyTo.name}</strong></span>
          <button style={s.cancelReply} onClick={() => { setReplyTo(null); setText(""); }}>✕</button>
        </div>
      )}

      {/* Input box */}
      <div style={s.inputWrap}>
        {currentUser ? (
          <div style={s.userAvatar}>
            {currentUser.photoURL
              ? <img src={currentUser.photoURL} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
              : (currentUser.displayName || "U")[0].toUpperCase()}
          </div>
        ) : (
          <div style={{ ...s.userAvatar, background: "var(--border)", color: "var(--mid)" }}>👤</div>
        )}
        <div style={s.inputRight}>
          <textarea
            ref={inputRef}
            style={s.textarea}
            rows={3}
            maxLength={500}
            placeholder={
              currentUser
                ? `Write a comment… use @${postAuthor} to tag the author`
                : "Log in to leave a comment"
            }
            value={text}
            disabled={!currentUser}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && e.ctrlKey) handleSubmit();
            }}
          />
          <div style={s.inputFooter}>
            <span style={s.hint}>Ctrl+Enter to submit · @name to mention</span>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <span style={s.charCount}>{text.length}/500</span>
              <button
                style={{ ...s.submitBtn, opacity: (!currentUser || submitting || !text.trim()) ? 0.5 : 1 }}
                disabled={!currentUser || submitting || !text.trim()}
                onClick={handleSubmit}>
                {submitting ? "Posting…" : "Post →"}
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Comments list */}
      {displayed.length === 0 ? (
        <div style={s.empty}>
          <span style={{ fontSize: "2rem" }}>🌱</span>
          <p>No comments yet. Be the first!</p>
        </div>
      ) : (
        <>
          <div style={s.list}>
            {visible.map((c) => (
              <CommentItem
                key={c.id}
                comment={c}
                canDelete={canDelete(c)}
                onDelete={() => handleDelete(c.id)}
                onMention={() => handleMention(c.name)}
              />
            ))}
          </div>

          {displayed.length > 5 && (
            <button style={s.showMoreBtn} onClick={() => setShowAll((v) => !v)}>
              {showAll ? "▲ Show less" : `▼ Show ${displayed.length - 5} more comments`}
            </button>
          )}
        </>
      )}
    </div>
  );
}

function CommentItem({ comment: c, canDelete, onDelete, onMention }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div style={s.comment}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}>
      {/* Avatar */}
      <div style={s.commentAvatar}>
        {c.photoURL
          ? <img src={c.photoURL} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }} />
          : (c.name || "?")[0].toUpperCase()}
      </div>

      {/* Body */}
      <div style={s.commentBody}>
        <div style={s.commentHeader}>
          <span style={s.commentName}>{c.name}</span>
          {c.replyTo && (
            <span style={s.replyingTo}>↩ @{c.replyTo}</span>
          )}
          <span style={s.commentTime}>{timeAgo(c.createdAt)}</span>

          {/* Action buttons on hover */}
          <div style={{ ...s.commentActions, opacity: hovered ? 1 : 0 }}>
            <button style={s.actionPill} onClick={onMention} title="Mention this person">
              @ Reply
            </button>
            {canDelete && (
              <button style={{ ...s.actionPill, color: "#ef4444" }} onClick={onDelete} title="Delete">
                🗑️
              </button>
            )}
          </div>
        </div>

        <p style={s.commentText}>
          <RenderText text={c.text} />
        </p>
      </div>
    </div>
  );
}

